import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---------- Base premiums (single item, only processing fee added) ----------
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single sword → premium 105 G (100 base + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it("single amulet → premium 65 G (60 base + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });
  it("single staff → premium 85 G (80 base + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 85 }] });
  });
  it("single potion → premium 45 G (40 base + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 45 }] });
  });
  it.todo("single rune component → premium 30 G (25 base + 5 fee)");
  it.todo("single moonstone component → premium 30 G (25 base + 5 fee)");

  // ---------- Component blocks of 3 alike ----------
  it.todo("2 runes → 50 G base premium (no block)");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium");

  // ---------- 'Alike' components (❓ same type, not just family) ----------
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // ---------- Individual premium modifiers ----------
  it.todo("cursed sword (steel, enchant 3) → 100 + 50 curse + 5 fee = 155 G");
  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (100 + 30 + 5 = 135 G)");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge (105 G)");
  it.todo("sword enchant 5 and cursed → both surcharges apply (100 + 50 + 30 + 5 = 185 G)");
  it.todo("long-standing customer (exactly 2 years) → 20% loyalty discount applies");
  it.todo("first insurance surcharge (10%) applies to each item in a quote");

  // ---------- Multi-item modifier scope (❓ per-item vs policy-wide) ----------
  it.todo("policy with cursed sword + plain amulet → 210 G before fee = 215 G total (curse applies only to cursed item)");

  // ---------- Rounding in MHPCO's favor ----------
  it.todo("premium yielding 197.5 G → 198 G (rounded up)");
  it.todo("payout yielding 350.5 G → 350 G (rounded down)");

  // ---------- Integration examples ----------
  it.todo("newcomer (0 years) with cursed steel sword enchant 3 → premium 165 G");
  it.todo("long-standing customer (3 years), second contract, cursed steel sword enchant 7 → premium 160 G");

  // ---------- Claim processing: standard reimbursement ----------
  it.todo("regular sword (steel, enchant 3), damage 500 G → payout 400 G (500 − 100 deductible)");
  it.todo("rune damage 200 G → payout 100 G (no special clause: 200 − 100 deductible)");

  // ---------- Special clauses ----------
  it.todo("steel sword, enchant 9, damage 1000 G → payout 400 G (high-enchantment 50% then deductible)");
  it.todo("dragon-material sword, enchant 5, damage 800 G → payout 700 G (dragon: full, then deductible)");
  it.todo("dragon-material sword, enchant 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, enchant exactly 8, damage 1000 G → payout 400 G (high-enchantment wins)");

  // ---------- Deductible per damage event ----------
  it.todo("dragon attack damaging sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // ---------- Cap behaviour ----------
  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (premium 165 G) → cap 2000 G (based on unmodified insurance value)");
  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 G; block discount does not affect insurance sum");
  it.todo("sword policy (cap 2000), two successive 1500 G claims → first payout 1400 G remaining 600 G; second payout 600 G remaining 0 G");

  // ---------- Multiple items of the same type ----------
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack damaging both swords → each entry treated as separate damage with its own deductible");
  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero, claim rejected");

  // ---------- Edge cases ----------
  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with stderr message");
  it.todo("claim references an item not part of the policy → CLI exits non-zero with stderr message");
  it.todo("claim damage entry with negative amount → CLI exits non-zero with stderr message");
});

