const PROCESSING_FEE = 5;
const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;

const FIRST_INSURANCE_RATE = 0.1;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const groupBase = (type: string, count: number): number =>
  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
    ? BLOCK_BASE_PREMIUM
    : count * basePremiumFor(type);

const policyBase = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(items)) {
    total += groupBase(type, count);
  }
  return total;
};

const firstInsuranceSurcharge = (base: number): number =>
  base * FIRST_INSURANCE_RATE;

const quotePremium = (items: Item[]): number => {
  const base = policyBase(items);
  return Math.ceil(base + firstInsuranceSurcharge(base) + PROCESSING_FEE);
};

export const processScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
};

