const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);

const damagePayout = (damage: Damage): number => damage.amount - DEDUCTIBLE;

const claimPayout = (claim: ClaimStep): number =>
  claim.incident.damages.reduce((sum, d) => sum + damagePayout(d), 0);

type QuoteResult = { premium: number };
type ClaimResult = { payout: number; remainingCap: number };
type StepResult = QuoteResult | ClaimResult;

export const processScenario = (scenario: Scenario): unknown => {
  let priorQuotes = 0;
  const policyCaps = new Map<number, number>();
  const results: StepResult[] = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      const isFollowUp = priorQuotes > 0;
      priorQuotes += 1;
      policyCaps.set(index, CAP_MULTIPLIER * insuranceSum(step.items));
      return {
        premium: quotePremium(step.items, {
          customer: scenario.customer,
          isFollowUp,
        }),
      };
    }
    const cap = policyCaps.get(step.policy) ?? 0;
    const payout = claimPayout(step);
    const remainingCap = cap - payout;
    policyCaps.set(step.policy, remainingCap);
    return { payout, remainingCap };
  });
  return { results };
};

