  // ---------- Deductible per damage event ----------
  it("claim: dragon attack damages sword 500 + amulet 300 → payout 600 G, remaining 2600", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword" }, { type: "amulet" }],
